// Module-level in-memory store (persists for the lifetime of the worker instance)

export type Todo = {
  id: string;
  title: string;
};

export const todos: Todo[] = [];

"use server";

import { serverAction } from "rwsdk/worker";
import { todos } from "./store";

export const addTodo = serverAction(async (formData: FormData) => {
  const title = formData.get("title");
  if (typeof title === "string" && title.trim()) {
    todos.push({ id: crypto.randomUUID(), title: title.trim() });
  }
});

export const deleteTodo = serverAction(async (formData: FormData) => {
  const id = formData.get("id");
  if (typeof id === "string") {
    const index = todos.findIndex((t) => t.id === id);
    if (index !== -1) {
      todos.splice(index, 1);
    }
  }
});

import { todos } from "./store";
import { addTodo, deleteTodo } from "./actions";

export const TodosPage = () => {
  return (
    <div>
      <h1>Todos</h1>
      <ul>
        {todos.map((todo) => (
          <li key={todo.id} data-testid="todo-item">
            <span>{todo.title}</span>
            <form action={deleteTodo} style={{ display: "inline" }}>
              <input type="hidden" name="id" value={todo.id} />
              <button type="submit">Delete</button>
            </form>
          </li>
        ))}
      </ul>
      <form action={addTodo}>
        <input name="title" type="text" placeholder="New todo..." />
        <button type="submit">Add Todo</button>
      </form>
    </div>
  );
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { TodosPage } from "@/app/pages/todos/TodosPage";
import { todos } from "@/app/pages/todos/store";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  route("/todos.json", () => {
    return Response.json({ todos });
  }),
  route("/todos.reset", {
    post: () => {
      todos.splice(0, todos.length);
      return new Response("reset");
    },
  }),
  render(Document, [
    route("/", Home),
    route("/todos", () => <TodosPage />),
  ]),
]);
